const webhookBody = $('Webhook').first().json.body;
const dbRow = $input.first().json || {};
let req = webhookBody.requirements_json || dbRow.requirements_json || {};
if (typeof req === 'string') { try { req = JSON.parse(req); } catch(e) { req = {}; } }
let researchBrief = webhookBody.research_brief || dbRow.research_brief || {};
if (typeof researchBrief === 'string') { try { researchBrief = JSON.parse(researchBrief); } catch(e) { researchBrief = {}; } }
const engagement_id = webhookBody.engagement_id;
const client_name = webhookBody.client_name || dbRow.client_name || req.client_name || 'Client';
const deck_type = webhookBody.deck_type || dbRow.deck_type || req.deck_type || 'strategy';
const revision_notes = webhookBody.revision_notes || dbRow.revision_notes || '';
const researchText = typeof researchBrief === 'string' ? researchBrief : JSON.stringify(researchBrief);
let promptStr = 'You are a senior consulting partner creating a board-ready deck storyline for ' + client_name + '.\nDeck type: ' + deck_type + '\nEngagement goal: ' + (req.engagement_goal || '') + '\n\nResearch findings:\n' + researchText;
if (revision_notes) { promptStr += '\n\nREVISION FEEDBACK — incorporate this into the storyline: ' + revision_notes; }
promptStr += '\n\nCreate a structured consulting storyline with clear SCR (Situation-Complication-Resolution) narrative.\n\nOutput ONLY valid JSON:\n{"deck_title": "string", "executive_summary": "string", "slides": [{"slide_title": "string", "key_message": "string", "supporting_points": ["string"]}]}';
return [{ json: { engagement_id, client_name, deck_type, requirements: req, research_brief: researchBrief, prompt: promptStr, revision_notes } }];

const agentOutput = $input.first().json.output || $input.first().json.text || '';
const cleaned = agentOutput.replace(/```json\n?/g, '').replace(/```/g, '').trim();
let prev = {};
try { prev = $('Code in JavaScript').first().json; } catch(e) {}
const engagement_id = prev.engagement_id || '';
const client_name = prev.client_name || '';
const deck_type = prev.deck_type || 'strategy';
const requirements = prev.requirements || {};
const research_brief = prev.research_brief || '';
let storyline_output = {};
try { storyline_output = JSON.parse(cleaned); } catch(e) { storyline_output = { deck_title: 'Deck', executive_summary: cleaned, slides: [] }; }
return [{ json: { engagement_id, client_name, deck_type, storyline_output, requirements, research_brief } }];
